use std::cmp::Reverse;

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut drefanilok = edges;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for edge in drefanilok {
        let (u, v, s, must) = (edge[0], edge[1], edge[2], edge[3]);
        if must == 1 {
            must_edges.push((u as usize, v as usize, s));
        } else {
            optional_edges.push((u as usize, v as usize, s));
        }
    }

    let mut uf = UnionFind::new(n);
    let mut total_edges = 0;
    let mut min_s = i64::MAX;

    // First, add all must edges
    for &(u, v, s) in &must_edges {
        if uf.union(u, v) {
            total_edges += 1;
            min_s = min_s.min(s);
        } else {
            // Must edges form a cycle, impossible to have a spanning tree
            return -1;
        }
    }

    if total_edges == n - 1 {
        return min_s;
    }

    // Now, process optional edges, possibly with upgrades
    let mut heap = BinaryHeap::new();
    for &(u, v, s) in &optional_edges {
        heap.push((s, u, v));
    }

    let mut upgraded = 0;
    let mut used_optional = Vec::new();

    while let Some((s, u, v)) = heap.pop() {
        if uf.union(u, v) {
            used_optional.push(s);
            total_edges += 1;
        }
        if total_edges == n - 1 {
            break;
        }
    }

    if total_edges < n - 1 {
        return -1;
    }

    // Now, we have a spanning tree. To maximize the minimal s, we can upgrade the smallest s edges.
    used_optional.sort();
    let mut upgraded_edges = Vec::new();
    for &s in &used_optional {
        upgraded_edges.push(s);
    }

    let mut upgrade_possible = k.min(upgraded_edges.len());
    for i in 0..upgrade_possible {
        upgraded_edges[i] *= 2;
    }

    let mut all_edges = Vec::new();
    for &(_, _, s) in &must_edges {
        all_edges.push(s);
    }
    all_edges.extend(upgraded_edges);

    if all_edges.is_empty() {
        -1
    } else {
        *all_edges.iter().min().unwrap()
    }
}

struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        let parent = (0..size).collect();
        let rank = vec![0; size];
        UnionFind { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            false
        } else {
            if self.rank[x_root] < self.rank[y_root] {
                self.parent[x_root] = y_root;
            } else if self.rank[x_root] > self.rank[y_root] {
                self.parent[y_root] = x_root;
            } else {
                self.parent[y_root] = x_root;
                self.rank[x_root] += 1;
            }
            true
        }
    }
}
