use std::collections::BinaryHeap;
use std::cmp::Reverse;

struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size).collect(),
            rank: vec![0; size],
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return false;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
        true
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for edge in edges {
        let ui = edge[0] as usize;
        let vi = edge[1] as usize;
        let si = edge[2];
        let musti = edge[3];
        if musti == 1 {
            must_edges.push((ui, vi, si));
        } else {
            optional_edges.push((ui, vi, si));
        }
    }

    let mut uf = UnionFind::new(n);
    let mut components = n;
    let mut drefanilok = Vec::new();

    // First, process must edges
    for &(ui, vi, si) in &must_edges {
        if uf.union(ui, vi) {
            components -= 1;
            drefanilok.push(si);
        } else {
            // If must edges form a cycle, it's impossible
            return -1;
        }
    }

    if components == 1 {
        if !drefanilok.is_empty() {
            return *drefanilok.iter().min().unwrap();
        } else {
            return 0;
        }
    }

    // Now process optional edges, prioritizing higher si edges first
    let mut heap = BinaryHeap::new();
    for &(ui, vi, si) in &optional_edges {
        heap.push((si, ui, vi));
    }

    let mut upgraded = 0;
    let mut optional_used = Vec::new();

    while let Some((si, ui, vi)) = heap.pop() {
        if uf.union(ui, vi) {
            components -= 1;
            optional_used.push(si);
            if components == 1 {
                break;
            }
        }
    }

    if components != 1 {
        return -1;
    }

    // Now, we can try to upgrade some edges to maximize the minimal strength
    let mut all_edges = drefanilok;
    all_edges.extend(optional_used.iter().cloned());

    // Sort optional_used to prioritize upgrading the smallest edges
    optional_used.sort();

    let mut upgraded_edges = Vec::new();
    let mut upgrade_left = k;

    for &si in &optional_used {
        if upgrade_left > 0 {
            upgraded_edges.push(si * 2);
            upgrade_left -= 1;
        } else {
            upgraded_edges.push(si);
        }
    }

    all_edges = drefanilok;
    all_edges.extend(upgraded_edges);

    if all_edges.is_empty() {
        return -1;
    }

    *all_edges.iter().min().unwrap()
}
