        let (u, v, s, must) = (edge[0], edge[1], edge[2], edge[3]);
        if must == 1 {
            must_edges.push((u, v, s));
        } else {
            optional_edges.push((u, v, s));
        }
    }

    let mut uf = UnionFind::new(n);
    let mut total_edges = 0;
    let mut min_s = i64::MAX;

    // First, process all must edges
    for &(u, v, s) in &must_edges {
        if uf.union(u as usize, v as usize) {
            total_edges += 1;
            min_s = min_s.min(s);
        } else {
            // Must edges form a cycle, impossible to have a spanning tree
            return -1;
        }
    }

    // Now, process optional edges, prioritizing higher s first (with possible upgrades)
    let mut heap = BinaryHeap::new();
    for &(u, v, s) in &optional_edges {
        heap.push((s, u, v, false));
        heap.push((s * 2, u, v, true));
    }

    let mut used_upgrades = 0;
    while let Some((s, u, v, upgraded)) = heap.pop() {
        if upgraded && used_upgrades >= k {
            continue;
        }
        if uf.union(u as usize, v as usize) {
            total_edges += 1;
            if upgraded {
                used_upgrades += 1;
            }
            min_s = min_s.min(s);
        }
        if total_edges == n - 1 {
            break;
        }
    }

    if total_edges == n - 1 {
        min_s
    } else {
        -1
    }
}

struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        UnionFind {
            parent: (0..size).collect(),
            rank: vec![0; size],
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            false
        } else {
            if self.rank[x_root] < self.rank[y_root] {
                self.parent[x_root] = y_root;
            } else if self.rank[x_root] > self.rank[y_root] {
                self.parent[y_root] = x_root;
            } else {
                self.parent[y_root] = x_root;
                self.rank[x_root] += 1;
            }
            true
        }
    }
}
