    // We want to maximize the minimal strength, so we should pick the largest possible edges
    // and upgrade the best candidates (optional edges with highest s)

    // Sort optional edges by descending s
    optional_edges.sort_by(|a, b| b.2.cmp(&a.2));

    // We can upgrade up to k optional edges (those with highest s)
    let mut upgraded_optional = Vec::new();
    let mut unupgraded_optional = Vec::new();
    for (i, &(u, v, s)) in optional_edges.iter().enumerate() {
