    all_edges.sort_by(|a, b| b.2.cmp(&a.2));

    // Reset Union-Find
    parent = (0..n).collect::<Vec<_>>();
    rank = vec![0; n];

    let mut selected_edges = Vec::new();
    for &(u, v, s) in &all_edges {
        if find(u, &mut parent) != find(v, &mut parent) {
            union(u, v, &mut parent, &mut rank);
            selected_edges.push(s);
        }
    }

    if selected_edges.len() == n - 1 {
        *selected_edges.iter().min().unwrap_or(&-1)
    } else {
