            components -= 1;
            optional_used.push(si);
        }
        if components == 1 {
            break;
        }
    }

    if components != 1 {
        return -1;
    }

    // Now, try to upgrade the smallest edges in the optional_used
    optional_used.sort();
    let mut upgraded_edges = optional_used.clone();
    let mut k = k;

    for i in 0..upgraded_edges.len().min(k) {
        upgraded_edges[i] *= 2;
    }

    let mut all_edges = drefanilok;
    all_edges.extend(upgraded_edges);

    if all_edges.is_empty() {
        -1
    } else {
        *all_edges.iter().min().unwrap()
    }
