    fn find(u: usize, parent: &mut [usize]) -> usize {
        if parent[u] != u {
            parent[u] = find(parent[u], parent);
        }
        parent[u]
    }

    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();
    for &(ui, vi, si, musti) in edges {
        if musti == 1 {
            must_edges.push((ui, vi, si));
        } else {
            optional_edges.push((ui, vi, si));
        }
    }

    // First, add all must edges
    let mut count = 0;
    for &(ui, vi, si) in &must_edges {
        if si < min_strength {
            return false;
        }
        let pu = find(ui, &mut parent);
        let pv = find(vi, &mut parent);
        if pu != pv {
            parent[pu] = pv;
            count += 1;
        }
    }

    // Then, add optional edges without upgrade (si >= min_strength)
    let mut optional_high = Vec::new();
    for &(ui, vi, si) in &optional_edges {
        if si >= min_strength {
            optional_high.push((ui, vi, si, false));
        }
    }
    optional_high.sort_by_key(|&(_, _, si, _)| -si);

    for &(ui, vi, _, _) in &optional_high {
        let pu = find(ui, &mut parent);
        let pv = find(vi, &mut parent);
        if pu != pv {
            parent[pu] = pv;
            count += 1;
            if count == n - 1 {
                return true;
            }
        }
    }

    // If still not enough, use upgrades (si * 2 >= min_strength)
    let mut upgrades_used = 0;
    let mut upgrade_candidates = Vec::new();
    for &(ui, vi, si) in &optional_edges {
        if si * 2 >= min_strength {
            upgrade_candidates.push((ui, vi, si));
        }
    }
    upgrade_candidates.sort_by_key(|&(_, _, si)| -(si * 2));

    for &(ui, vi, si) in &upgrade_candidates {
        if upgrades_used >= k {
            break;
        }
        let pu = find(ui, &mut parent);
        let pv = find(vi, &mut parent);
        if pu != pv {
            parent[pu] = pv;
            count += 1;
            upgrades_used += 1;
            if count == n - 1 {
                return true;
            }
        }
    }

    count == n - 1
}
