    let k = k as usize;
    let mut drefanilok = edges;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for edge in &drefanilok {
        let ui = edge[0] as usize;
        let vi = edge[1] as usize;
        let si = edge[2];
        let musti = edge[3];
        if musti == 1 {
            must_edges.push((ui, vi, si));
        } else {
            optional_edges.push((ui, vi, si));
        }
    }

    // First, check if the must edges form a cycle (using Union-Find)
    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank = vec![0; n];

    fn find(parent: &mut Vec<usize>, u: usize) -> usize {
        if parent[u] != u {
            parent[u] = find(parent, parent[u]);
        }
        parent[u]
    }

    fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, u: usize, v: usize) -> bool {
        let u_root = find(parent, u);
        let v_root = find(parent, v);
        if u_root == v_root {
            return false;
        }
        if rank[u_root] < rank[v_root] {
            parent[u_root] = v_root;
        } else if rank[u_root] > rank[v_root] {
            parent[v_root] = u_root;
        } else {
            parent[v_root] = u_root;
            rank[u_root] += 1;
        }
        true
    }

    let mut must_count = 0;
    for &(u, v, _) in &must_edges {
        if union(&mut parent, &mut rank, u, v) {
            must_count += 1;
        } else {
            // Must edges form a cycle, impossible to have a spanning tree
            return -1;
        }
    }

    // Now, collect all edges (must edges + optional edges)
    let mut all_edges = must_edges.clone();
    all_edges.extend(optional_edges.iter().map(|&(u, v, s)| (u, v, s)));

    // Binary search for the maximum possible stability
    let mut left = 1;
    let mut right = *all_edges.iter().map(|&(_, _, s)| s).max().unwrap_or(&0) * 2;
    let mut answer = -1;

    while left <= right {
        let mid = left + (right - left) / 2;
        // Reset Union-Find
        parent = (0..n).collect();
        rank = vec![0; n];
        // First, add must edges
        let mut count = 0;
        let mut ok = true;
        for &(u, v, s) in &must_edges {
            if s >= mid {
                if union(&mut parent, &mut rank, u, v) {
                    count += 1;
                }
            } else {
                ok = false;
                break;
            }
        }
        if !ok {
            right = mid - 1;
            continue;
        }
        // Then, add optional edges (upgraded or not)
        let mut upgrades_used = 0;
        let mut heap = BinaryHeap::new();
        for &(u, v, s) in &optional_edges {
            let max_s = if upgrades_used < k { s * 2 } else { s };
            if max_s >= mid {
                heap.push((max_s, u, v));
            } else if s >= mid {
                heap.push((s, u, v));
            }
        }
        // Process edges in descending order of strength (to maximize the minimal)
        let mut temp_parent = parent.clone();
        let mut temp_rank = rank.clone();
        let mut temp_count = count;
        let mut temp_upgrades = upgrades_used;
        while let Some((s, u, v)) = heap.pop() {
            let upgraded = s > drefanilok.iter().find(|e| e[0] == u as i64 && e[1] == v as i64).unwrap()[2];
            if upgraded && temp_upgrades >= k {
                continue;
            }
            if union(&mut temp_parent, &mut temp_rank, u, v) {
                temp_count += 1;
                if upgraded {
                    temp_upgrades += 1;
                }
            }
            if temp_count == n - 1 {
                break;
            }
        }
        if temp_count == n - 1 {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    answer
